            // 
            // TotalCostPerc_CF
            // 
            this.TotalCostPerc_CF.DataMember = "SR_FM_Stocktaking";
            this.TotalCostPerc_CF.DisplayName = "TotalCostPerc_CF";
            this.TotalCostPerc_CF.Expression = "(ToDecimal([TotalCost]) / ToDecimal(Sum([TotalCost])))*ToDecimal(100)\n";
            this.TotalCostPerc_CF.Name = "TotalCostPerc_CF";
            // 
            // Per_Chick_CF
            // 
            this.Per_Chick_CF.DataMember = "SR_FM_Stocktaking";
            this.Per_Chick_CF.Expression = "Iif([FemaleChicks]!=0,[TotalCost]/[FemaleChicks] ,[FemaleChicks] )";
            this.Per_Chick_CF.Name = "Per_Chick_CF";
            // 
            // PerHH_CF
            // 
            this.PerHH_CF.DataMember = "SR_FM_Stocktaking";
            this.PerHH_CF.DisplayName = "PerHH_CF";
            this.PerHH_CF.Expression = "Iif([FemalePOL]!=0,[TotalCost]/[FemalePOL] ,[FemalePOL] )\n";
            this.PerHH_CF.Name = "PerHH_CF";
            // 
            // PerHE_CF
            // 
            this.PerHE_CF.DataMember = "SR_FM_Stocktaking";
            this.PerHE_CF.Expression = "Iif([HatchingEggs]!=0,[TotalCost]/[HatchingEggs] ,[HatchingEggs] )\n\n";
            this.PerHE_CF.Name = "PerHE_CF";
            // 
            // DiffQtyq
            // 
            this.DiffQtyq.DataMember = "SR_FM_Stocktaking";
            this.DiffQtyq.Expression = "IsNull([ActualQty], 0) - IsNull([SentOrClacQty], 0)";
            this.DiffQtyq.Name = "DiffQtyq";
            // 
            // DiffPriceq
            // 
            this.DiffPriceq.DataMember = "SR_FM_Stocktaking";
            this.DiffPriceq.Expression = "Iif([CalcPriceUnit] > 0, IsNull([AdjustedPriceUnit], 0) - IsNull([CalcPriceUnit]," +
    " 0), 0)";
            this.DiffPriceq.Name = "DiffPriceq";
            // 
            // ActEggRecHHCum
            // 
            this.ActEggRecHHCum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.ActEggRecHHCum.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] <> 0, [SR_HT_WeeklyHHFlockSum.ActRecEggs] / [SR_" +
    "HT_WeeklyHHFlockSum.POL], 0)\n";
            this.ActEggRecHHCum.Name = "ActEggRecHHCum";
            // 
            // RejEggHHCum
            // 
            this.RejEggHHCum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.RejEggHHCum.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] <> 0, [SR_HT_WeeklyHHFlockSum.RejEggs] / [SR_HT_" +
    "WeeklyHHFlockSum.POL], 0)\n";
            this.RejEggHHCum.Name = "RejEggHHCum";
            // 
            // EstHatEggs
            // 
            this.EstHatEggs.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.EstHatEggs.Expression = "[ActEggRecHHCum] - [RejEggHHCum]\n";
            this.EstHatEggs.Name = "EstHatEggs";
            // 
            // ActEggSetHHCum
            // 
            this.ActEggSetHHCum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.ActEggSetHHCum.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] <> 0, [SR_HT_WeeklyHHFlockSum.ActSetEggCum] / [S" +
    "R_HT_WeeklyHHFlockSum.POL], 0)\n";
            this.ActEggSetHHCum.Name = "ActEggSetHHCum";
            // 
            // EstHatEggsBefore21days
            // 
            this.EstHatEggsBefore21days.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.EstHatEggsBefore21days.Expression = "[SR_HT_WeeklyHHFlockSum.ActRecEggsBefore21days] - [SR_HT_WeeklyHHFlockSum.RejEggs" +
    "Before21days]\n";
            this.EstHatEggsBefore21days.Name = "EstHatEggsBefore21days";
            // 
            // ActHatch_Per_Cum
            // 
            this.ActHatch_Per_Cum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.ActHatch_Per_Cum.Expression = resources.GetString("ActHatch_Per_Cum.Expression");
            this.ActHatch_Per_Cum.Name = "ActHatch_Per_Cum";
            // 
            // EstChiks
            // 
            this.EstChiks.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.EstChiks.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] > 0, \n    ([EstHatEggsBefore21days] * [ActHatch_" +
    "Per_Cum] / 100) / [SR_HT_WeeklyHHFlockSum.POL], \n    0)\n";
            this.EstChiks.Name = "EstChiks";
            // 
            // ActChicksHHCum
            // 
            this.ActChicksHHCum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.ActChicksHHCum.Expression = resources.GetString("ActChicksHHCum.Expression");
            this.ActChicksHHCum.Name = "ActChicksHHCum";
            // 
            // Diviation
            // 
            this.Diviation.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.Diviation.Expression = "[ActHatch_Per_Cum] - [SR_HT_WeeklyHHFlockSum.StdHatchCum]\n";
            this.Diviation.Name = "Diviation";
            // 
            // TotalHatchedEggs
            // 
            this.TotalHatchedEggs.DataMember = "SR_HT_Production";
            this.TotalHatchedEggs.Expression = "[ChicksSettedEggs]";
            this.TotalHatchedEggs.Name = "TotalHatchedEggs";
            // 
            // HatchPer
            // 
            this.HatchPer.DataMember = "SR_HT_Production";
            this.HatchPer.Expression = "Iif([TotalHatchedEggs] <> 0, [SR_HT_Production.Chicks] * 100 / [TotalHatchedEggs]" +
    ", 0)\n";
            this.HatchPer.Name = "HatchPer";
            // 
            // HOFPer
            // 
            this.HOFPer.DataMember = "SR_HT_Production";
            this.HOFPer.Expression = "Iif([SR_HT_Production.FertPer] <> 0, [HatchPer] * 100.0 / [SR_HT_Production.FertP" +
    "er], 0)\n";
            this.HOFPer.Name = "HOFPer";
            // 
            // HatchPerc
            // 
            this.HatchPerc.DataMember = "SR_HT_Hatch";
            this.HatchPerc.Expression = "Iif([SR_HT_Hatch.SettedEggs] <> 0, [SR_HT_Hatch.SellableChicks] * 100 / [SR_HT_Ha" +
    "tch.SettedEggs], 0)\n";
            this.HatchPerc.Name = "HatchPerc";
            // 
            // HOFPerc
            // 
            this.HOFPerc.DataMember = "SR_HT_Hatch";
            this.HOFPerc.Expression = "Iif([SR_HT_Hatch.FertPer] <> 0, [HatchPer] * 100.0 / [SR_HT_Hatch.FertPer], 0)\n";
            this.HOFPerc.Name = "HOFPerc";
            // 
            // TotalHatchPerc
            // 
            this.TotalHatchPerc.DataMember = "SR_HT_Hatch";
            this.TotalHatchPerc.Expression = "Iif(Sum([SR_HT_Hatch.SettedEggs]) <> 0, Sum([SR_HT_Hatch.SellableChicks]) * 100 /" +
    " Sum([SR_HT_Hatch.SettedEggs]), 0)\n";
            this.TotalHatchPerc.Name = "TotalHatchPerc";
            // 
            // FertileEggs_CF
            // 
            this.FertileEggs_CF.DataMember = "SR_HT_Hatch";
            this.FertileEggs_CF.Expression = "[SR_HT_Hatch.FertPer] * [SR_HT_Hatch.SettedEggs] / 100\n\n";
            this.FertileEggs_CF.Name = "FertileEggs_CF";
            // 
            // FertPerc
            // 
            this.FertPerc.DataMember = "SR_HT_Hatch";
            this.FertPerc.Expression = "Iif(Sum([SR_HT_Hatch.SettedEggs]) <> 0, Sum([FertileEggs]) * 100 / Sum([SR_HT_Hat" +
    "ch.SettedEggs]), 0)\n";
            this.FertPerc.Name = "FertPerc";
            // 
            // TotalHOFPerc
            // 
            this.TotalHOFPerc.DataMember = "SR_HT_Hatch";
            this.TotalHOFPerc.Expression = "Iif([FertPerc] <> 0, [TotalHatchPerc] * 100 / [FertPerc], 0)\n";
            this.TotalHOFPerc.Name = "TotalHOFPerc";
            // 
            // SettedAndRejEggs
            // 
            this.SettedAndRejEggs.DataMember = "SR_HT_DailyHatchWise";
            this.SettedAndRejEggs.Expression = "[SettedEggs] + [RejSellEggs] + [RejUnSellEggs]";
            this.SettedAndRejEggs.Name = "SettedAndRejEggs";
            // 
            // RejSellEggsPerc
            // 
            this.RejSellEggsPerc.DataMember = "SR_HT_DailyHatchWise";
            this.RejSellEggsPerc.Expression = "Iif([SettedAndRejEggs], [RejSellEggs] / [SettedAndRejEggs] * 100 , 0)";
            this.RejSellEggsPerc.Name = "RejSellEggsPerc";
            // 
            // BrokenPerc
            // 
            this.BrokenPerc.DataMember = "SR_HT_DailyHatchWise";
            this.BrokenPerc.Expression = "Iif([SettedAndRejEggs], [RejUnSellEggs] / [SettedAndRejEggs] * 100 , 0)\n";
            this.BrokenPerc.Name = "BrokenPerc";
            // 
            // InfertilePerc
            // 
            this.InfertilePerc.DataMember = "SR_HT_DailyHatchWise";
            this.InfertilePerc.Expression = "Iif([SettedEggs] > 0, [InfertileEggs] / [SettedEggs] * 100,0 )";
            this.InfertilePerc.Name = "InfertilePerc";
            // 
            // NonHatchEggPerc
            // 
            this.NonHatchEggPerc.DataMember = "SR_HT_DailyHatchWise";
            this.NonHatchEggPerc.Expression = "Iif([SettedEggs]> 0, [FertileEggs] / [SettedEggs], 0)";
            this.NonHatchEggPerc.Name = "NonHatchEggPerc";
            // 
            // TotalHatchChicks
            // 
            this.TotalHatchChicks.DataMember = "SR_HT_DailyHatchWise";
            this.TotalHatchChicks.Expression = "[Culls] + [SellableChicks]";
            this.TotalHatchChicks.Name = "TotalHatchChicks";
            // 
            // DeadPerc
            // 
            this.DeadPerc.DataMember = "SR_HT_DailyHatchWise";
            this.DeadPerc.Expression = "Iif([SettedEggs] > 0, [Deads] / [SettedEggs],0 )";
            this.DeadPerc.Name = "DeadPerc";
            // 
            // CullsPerc
            // 
            this.CullsPerc.DataMember = "SR_HT_DailyHatchWise";
            this.CullsPerc.Expression = "Iif([SettedEggs] > 0, [Culls] / [SettedEggs], 0)";
            this.CullsPerc.Name = "CullsPerc";
            // 
            // ChicksPerc
            // 
            this.ChicksPerc.DataMember = "SR_HT_DailyHatchWise";
            this.ChicksPerc.Expression = "Iif([SettedEggs] > 0, [SellableChicks] / [SettedEggs], 0)\n";
            this.ChicksPerc.Name = "ChicksPerc";
            // 
            // AllOverSettedPerc
            // 
            this.AllOverSettedPerc.DataMember = "SR_HT_DailyHatchWise";
            this.AllOverSettedPerc.Expression = "Iif([SettedEggs] > 0, [TotalHatchChicks] / [SettedEggs], 0)\n";
            this.AllOverSettedPerc.Name = "AllOverSettedPerc";
            // 
            // SaleOverFertilePerc
            // 
            this.SaleOverFertilePerc.DataMember = "SR_HT_DailyHatchWise";
            this.SaleOverFertilePerc.Expression = "Iif([FertileEggs] > 0, [SellableChicks] / [FertileEggs] * 100, 0)\n";
            this.SaleOverFertilePerc.Name = "SaleOverFertilePerc";
            // 
            // RejSellEggsPerc_Total
            // 
            this.RejSellEggsPerc_Total.DataMember = "SR_HT_DailyHatchWise";
            this.RejSellEggsPerc_Total.Expression = "Iif(\n    Sum([SettedAndRejEggs]) > 0,\n    Sum([RejSellEggs]) / Sum([SettedAndRejE" +
    "ggs]) * 100,\n    0\n)\n";
            this.RejSellEggsPerc_Total.Name = "RejSellEggsPerc_Total";
            // 
            // BrokenPerc_Total
            // 
            this.BrokenPerc_Total.DataMember = "SR_HT_DailyHatchWise";
            this.BrokenPerc_Total.Expression = "Iif(\n    Sum([SettedAndRejEggs]) > 0,\n    Sum([RejUnSellEggs]) / Sum([SettedAndRe" +
    "jEggs]) * 100,\n    0\n)\n";
            this.BrokenPerc_Total.Name = "BrokenPerc_Total";
            // 
            // InfertilePerc_Total
            // 
            this.InfertilePerc_Total.DataMember = "SR_HT_DailyHatchWise";
            this.InfertilePerc_Total.Expression = "Iif(\n    Sum([SettedEggs]) > 0,\n    Sum([InfertileEggs]) / Sum([SettedEggs]) * 10" +
    "0,\n    0\n)\n";
            this.InfertilePerc_Total.Name = "InfertilePerc_Total";
            // 
            // NonHatchEggsPerc_Total
            // 
            this.NonHatchEggsPerc_Total.DataMember = "SR_HT_DailyHatchWise";
            this.NonHatchEggsPerc_Total.Expression = "Iif(\n    Sum([SettedEggs]) > 0,\n    Sum([NonHatEggs]) / Sum([SettedEggs]) * 100,\n" +
    "    0\n)\n";
            this.NonHatchEggsPerc_Total.Name = "NonHatchEggsPerc_Total";
            // 
            // DeadPerc_Total
            // 
            this.DeadPerc_Total.DataMember = "SR_HT_DailyHatchWise";
            this.DeadPerc_Total.Expression = "Iif(\n    Sum([SettedEggs]) > 0,\n    Sum([Deads]) / Sum([SettedEggs]) * 100,\n    0" +
    "\n)\n";
            this.DeadPerc_Total.Name = "DeadPerc_Total";
            // 
            // CullsPerc_Totaal
            // 
            this.CullsPerc_Totaal.DataMember = "SR_HT_DailyHatchWise";
            this.CullsPerc_Totaal.DataSource = this.dsFinance;
            this.CullsPerc_Totaal.Expression = "Iif(\n    Sum([SettedEggs]) > 0,\n    Sum([Culls]) / Sum([SettedEggs]) * 100,\n    0" +
    "\n)\n";
            this.CullsPerc_Totaal.Name = "CullsPerc_Totaal";
